function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp_up[i]: Maximum score of a valid subsequence ending at index i,
    // where the last transition was an increase (i.e., a[i] > a[j] where j < i is not the case,
    // but rather the sequence ends with ... < a[i]).
    // This means the element before a[i] must be smaller than a[i].
    // The sequence must follow the pattern: < > < > ... or > < > < ...
    // If the sequence ends with '<', the previous element must be smaller.
    // If the sequence ends with '>', the previous element must be larger.

    // Let's redefine the DP states based on the required pattern:
    // 1. Ending with < (Up move): The element before must be strictly smaller. (a[j] < a[i])
    // 2. Ending with > (Down move): The element before must be strictly larger. (a[j] > a[i])

    // dp_up[i]: Max score of a valid alternating subsequence ending at i, where nums[i] is greater than the previous element. (..., < nums[i])
    const dp_up = new Array(n).fill(nums[0]);

    // dp_down[i]: Max score of a valid alternating subsequence ending at i, where nums[i] is smaller than the previous element. (..., > nums[i])
    const dp_down = new Array(n).fill(nums[0]);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: A subsequence of length 1 always exists, score is nums[i]
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        for (let j = 0; j < i; j++) {
            // Distance constraint: i - j >= k
            if (i - j >= k) {
                const num_i = nums[i];
                const num_j = nums[j];

                // Case 1: Ending with an UP move at i (..., < num_i)
                // The sequence ending at j must have ended with a DOWN move (..., > num_j)
                // Transition: num_j > num_k ... > num_j < num_i
                if (num_j < num_i) {
                    // We can extend a sequence ending at j with a DOWN move (dp_down[j])
                    // Or start a new sequence of length 2: (num_j, num_i) where num_j < num_i.
                    // However, dp_down[j] already includes num_j.
                    // If dp_down[j] > nums[j] (meaning length > 1), we extend it.
                    // If dp_down[j] == nums[j] (meaning length = 1, sequence is just [num_j]),
                    // then extending it gives score num_j + num_i.

                    // The state definition handles this: 
                    // dp_down[j] is the max score ending at j. We add nums[i] to it.
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + num_i);
                }

                // Case 2: Ending with a DOWN move at i (..., > num_i)
                // The sequence ending at j must have ended with an UP move (..., < num_j)
                // Transition: num_j < num_k ... < num_j > num_i
                if (num_j > num_i) {
                    // We can extend a sequence ending at j with an UP move (dp_up[j])
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + num_i);
                }
            }
        }
        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}

