    // 1. Ending with < (Up move): The element before must be strictly smaller. (a[j] < a[i])
    // 2. Ending with > (Down move): The element before must be strictly larger. (a[j] > a[i])

    // dp_up[i]: Max score of a valid alternating subsequence ending at i, where nums[i] is greater than the previous element. (..., < nums[i])
    const dp_up = new Array(n).fill(nums[0]);

    // dp_down[i]: Max score of a valid alternating subsequence ending at i, where nums[i] is smaller than the previous element. (..., > nums[i])
    const dp_down = new Array(n).fill(nums[0]);

